import redis

# Configuration for Redis connection
REDIS_NODES = [
    {"host": "redis-node-1", "port": 6379},
    {"host": "redis-node-2", "port": 6379},
    {"host": "redis-node-3", "port": 6379}
]
PASSWORD = "your_redis_password"
TTL_SECONDS = 3600  # Time to live in seconds

# Initialize Redis connection pool
pool = redis.ConnectionPool(
    host=REDIS_NODES[0]['host'],
    port=REDIS_NODES[0]['port'],
    password=PASSWORD,
    decode_responses=True
)

def get_redis_client():
    return redis.Redis(connection_pool=pool)

def store_sensitive_data(key, value):
    client = get_redis_client()
    client.setex(key, TTL_SECONDS, value)

def retrieve_sensitive_data(key):
    client = get_redis_client()
    return client.get(key)

# Example usage
if __name__ == "__main__":
    session_token = "user_session_token_123"
    api_key = "user_api_key_456"

    store_sensitive_data("session:123", session_token)
    stored_session = retrieve_sensitive_data("session:123")
    print(f"Retrieved Session Token: {stored_session}")

    store_sensitive_data("api_key:456", api_key)
    stored_api_key = retrieve_sensitive_data("api_key:456")
    print(f"Retrieved API Key: {stored_api_key}")